/// Compute quickstart -- Phase 4.5.1 end-to-end example.
///
/// Defines a `NetworkStack` that provisions:
/// - a custom-mode VPC network (`main-vpc`),
/// - a regional external IPv4 address for a load balancer (`lb-vip-prod`),
///
/// demonstrating the `RoutingMode` / `AddressType` / `NetworkTier` enums
/// generated by Phase 4.5 Wave 0; enum values passed directly (Phase 4.5.1).
///
/// Wave 5 Batch 4 adds three compute-resource-scoped IAM member bindings
/// (instance, subnetwork, disk) -- each demonstrates the
/// "tightly scope permissions to a single VM / subnet / disk" pattern that
/// keeps service projects and tenants from over-reaching.
library;

import 'dart:convert' as dart_convert;
import 'dart:io';

import 'package:terradart_core/terradart_core.dart';
import 'package:terradart_google/compute.dart';
import 'package:terradart_google/provider.dart';

/// Network stack: a VPC + a public IP for a load balancer.
class NetworkStack extends Stack {
  NetworkStack({required String projectId})
      : super(
          providers: [
            GoogleProvider(project: projectId, region: 'asia-northeast1'),
          ],
        ) {
    final mainVpc = GoogleComputeNetwork(
      localName: 'main',
      name: TfArg.literal('main-vpc'),
      // Custom-mode VPC: no auto-subnets, explicit subnetwork resources.
      autoCreateSubnetworks: TfArg.literal(false),
      routingMode: TfArg.literal(RoutingMode.regional),
    );
    add(mainVpc);

    add(
      GoogleComputeAddress(
        localName: 'lb_vip',
        name: TfArg.literal('lb-vip-prod'),
        region: TfArg.literal('asia-northeast1'),
        addressType: TfArg.literal(AddressType.external),
        networkTier: TfArg.literal(NetworkTier.premium),
        ipVersion: TfArg.literal(IpVersion.ipv4),
      ),
    );

    // ---- Subnetwork for Shared VPC IAM demo -------------------------------
    //
    // A workload subnet that a service project will attach VMs to. The
    // binding below grants the service project's compute SA the right to
    // *only* this subnet rather than the whole VPC.

    final workloadSubnet = GoogleComputeSubnetwork(
      localName: 'workload',
      name: TfArg.literal('workload-subnet'),
      region: TfArg.literal('asia-northeast1'),
      network: TfArg.ref(mainVpc.id),
      ipCidrRange: TfArg.literal('10.10.0.0/20'),
    );
    add(workloadSubnet);

    // ---- IAM: subnetwork-scoped networkUser (Shared VPC) ------------------
    //
    // The classic Shared-VPC pattern: each service project's compute SA
    // gets `roles/compute.networkUser` on the exact subnets it can attach
    // to. Keeps cross-project tenants from spilling into the wrong region.

    add(
      GoogleComputeSubnetworkIamMember(
        localName: 'workload_subnet_user',
        subnetwork: TfArg.ref(workloadSubnet.nameRef),
        role: TfArg.literal('roles/compute.networkUser'),
        member: TfArg.literal(
          'serviceAccount:111111111111@cloudservices.gserviceaccount.com',
        ),
      ),
    );

    // ---- Bastion VM with instance-scoped IAM ------------------------------
    //
    // A single jump-host VM that an on-call group can power-cycle. The
    // binding grants `roles/compute.instanceAdmin.v1` on *only* this VM,
    // avoiding a project-wide compute admin role for what is really a
    // one-host operation.

    final bastion = GoogleComputeInstance(
      localName: 'bastion',
      name: TfArg.literal('ops-bastion'),
      machineType: TfArg.literal('e2-small'),
      zone: TfArg.literal('asia-northeast1-a'),
      bootDisk: const BootDisk(
        initializeParams: InitializeParams(
          image: 'debian-cloud/debian-12',
        ),
      ),
      networkInterface: [
        NetworkInterface(
          subnetwork: r'${google_compute_subnetwork.workload.self_link}',
        ),
      ],
    );
    add(bastion);

    add(
      GoogleComputeInstanceIamMember(
        localName: 'bastion_admin',
        instanceName: TfArg.ref(bastion.nameRef),
        role: TfArg.literal('roles/compute.instanceAdmin.v1'),
        member: TfArg.literal('group:on-call-sre@example.com'),
        zone: TfArg.literal('asia-northeast1-a'),
      ),
    );

    // ---- Disk-scoped IAM (backup-only access) -----------------------------
    //
    // A persistent data disk created out-of-band (gcloud / imported); the
    // backup tooling SA gets `roles/compute.storageAdmin` on *this one
    // disk* so it can snapshot it without project-wide disk admin. The
    // disk name is a string literal -- substitute the real disk resource
    // once it lands in the curated set.

    add(
      GoogleComputeDiskIamMember(
        localName: 'data_disk_backup',
        name: TfArg.literal('persistent-data-disk'),
        role: TfArg.literal('roles/compute.storageAdmin'),
        member: TfArg.literal('serviceAccount:backup@example.iam.gserviceaccount.com'),
        zone: TfArg.literal('asia-northeast1-a'),
      ),
    );
  }

  @override
  Future<void> synth({required String outDir}) async {
    final result = StackSynth.synth(this);
    await Directory(outDir).create(recursive: true);
    final tfFile = File('$outDir/main.tf.json');
    await tfFile.writeAsString(
      const dart_convert.JsonEncoder.withIndent('  ').convert(result.tfJson),
    );
  }
}
